mapper.select:
SELECT p.id AS productId, p.name AS productName, p.standard AS standard, u.name AS unitName, IFNULL(opening.openingStock, 0) AS openingStock, IFNULL(period.inboundStock, 0) AS inboundStock, IFNULL(period.outboundStock, 0) AS outboundStock, (IFNULL(opening.openingStock, 0) + IFNULL(period.inboundStock, 0) - IFNULL(period.outboundStock, 0)) AS closingStock FROM erp_product p LEFT JOIN erp_product_unit u ON u.id = p.unit_id AND u.deleted = 0
LEFT JOIN ( SELECT r1.product_id, r1.total_count AS openingStock FROM erp_stock_record r1 INNER JOIN ( SELECT product_id, MAX(id) AS max_id FROM erp_stock_record WHERE deleted = 0
AND create_time < #{req.beginTime}
GROUP BY product_id ) r2 ON r1.id = r2.max_id AND r1.deleted = 0 ) opening ON opening.product_id = p.id
LEFT JOIN ( SELECT product_id, SUM(CASE WHEN count > 0 THEN count ELSE 0 END) AS inboundStock, SUM(CASE WHEN count < 0 THEN ABS(count) ELSE 0 END) AS outboundStock FROM erp_stock_record WHERE deleted = 0
AND create_time >= #{req.beginTime}
AND create_time <= #{req.endTime}
AND warehouse_id = #{req.warehouseId}
GROUP BY product_id ) period ON period.product_id = p.id WHERE p.deleted = 0
AND p.id = #{req.productId}
HAVING openingStock > 0 OR inboundStock > 0 OR outboundStock > 0 ORDER BY p.id
